import django
from django.conf import settings
settings.configure(DEBUG=True, SECRET_KEY='test')
django.setup()

from django.views.debug import ExceptionReporter

# Simulate the scenario from the PR description
class MockRequest:
    META = {'SERVER_NAME': 'testserver', 'SERVER_PORT': '80'}
    GET = {}
    POST = {}
    COOKIES = {}
    FILES = {}
    path = '/test/'
    path_info = '/test/'
    method = 'GET'

try:
    try:
        raise RuntimeError('my error')
    except Exception as exc:
        raise ValueError('my new error') from None
except ValueError as e:
    reporter = ExceptionReporter(MockRequest(), None, e, None)
    frames = reporter.get_traceback_frames()
    print('Number of frames:', len(frames))
    for i, frame in enumerate(frames):
        print(f'Frame {i}: exc_cause={frame[\"exc_cause\"]!r}, exc_cause_explicit={frame[\"exc_cause_explicit\"]!r}')
    print()
    print('SUCCESS: The RuntimeError is NOT shown as the cause (since from None was used)')
    print('exc_cause should be None:', frames[0]['exc_cause'] is None if frames else 'no frames')
"
